<template>
  <!-- ==============================================
    ** Inner Banner **
    =================================================== -->
  <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>{{ tipo }} ABIERTOS EN LA CARRERA.</h1>

            <h4>
                  <router-link to="/">INICIO</router-link>
                </h4>
         
                <h3>{{ tipo }}</h3>
          </div>
        </div>
      </div>
    </div>
  </div>

  <!-- ==============================================
    ** News & Events **
    =================================================== -->
  <div class="container blog-wrapper padding-lg">
    <div class="row">
      <div class="col-sm-8 blog-left">
        <div v-if="Cursos.length == 0" class="col-12 justify-content-center">
          <h2>SIN {{ tipo }}</h2>
        </div>
        <ul v-else class="row news-listing">
          <li v-for="(cur, id_cur) of Cursos" :key="id_cur" v-show="(pag - 1) * NUM_RESULTS <= id_cur &&
            pag * NUM_RESULTS > id_cur
            " class="col-xs-6 col-sm-6 grid-item">
            <div class="inner">

              <router-link :to="'/detalleCurso/' + cur.iddetalle_cursos_academicos" @click="$store.commit('clickLink')">
                <img :src="url_api + '/Cursos/' + cur.det_img_portada" class="img-responsive" alt="" style="height: 400px;"/>
              </router-link>

              <div class="cnt-block" style="height: 250px;">
                <ul class="post-detail">
                  <li>
                    <span class="fa fa-clock-o"></span>
                    <span class="bold">Carga Horaria: </span> {{ cur.det_carga_horaria }} hrs académicas.
                  </li>
                  <li>
                    <span class="icon-date-icon ico"></span>
                    <span class="bold">Costo: </span> {{ cur.det_costo }} Bs
                  </li>

                </ul>
                <h2>
                  <router-link :to="'/detalleCurso/' +
                  cur.iddetalle_cursos_academicos
                  " @click="$store.commit('clickLink')" class="read-more">{{ cur.det_titulo }}
                </router-link>
                </h2>
                <div class="author media" v-for="(fac, id_fac) of cur.facilitadores" :key="id_fac">
                  <div class="media-left">
                    <img :src="url_api + '/Cursos/' + fac.foto_facilitador" alt="img" />
                  </div>
                  <div class="media-body align-self-center">
                    <p>{{ fac.nombre_facilitador }}</p>
                  </div>
                </div>

                <router-link :to="'/detalleCurso/' +
                  cur.iddetalle_cursos_academicos
                  " @click="$store.commit('clickLink')" class="read-more"><span
                    class="icon-play-icon"></span>
                  Leer más
                </router-link>
              </div>
            </div>
          </li>
        </ul>

        <div class="text-center">
          <ul class="pagination blue">
            <li class="pagination-arrow disable">
              <a href="#" aria-label="Previous" @click.prevent="pag != 1 ? (pag -= 1) : ''">
                <span aria-hidden="true">
                  <i class="fa fa-angle-left" aria-hidden="true">
                  </i>
                </span>
              </a>
            </li>

            <li v-for="(i, index) of pager" :key="index">
              <a href="#" :class="[i == pag ? 'active' : '']" @click.prevent="pag = i">
                {{ i }}
              </a>
            </li>

            <li>
              <a href="#" aria-label="Next" @click.prevent="pag != pager ? (pag += 1) : ''">
                <span aria-hidden="true">
                  <i class="fa fa-angle-right" aria-hidden="true">
                  </i>
                </span>
              </a>
            </li>
          </ul>
        </div>
      </div>

      <div class="col-sm-4">

        <SidebarCustom></SidebarCustom>

      </div>

    </div>


  </div>
</template>

<style scoped>
/* .image-container {
  width: 100%;
  height: 100%;
  overflow: hidden;
}

.thumbnail-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}
.bg-overlay-img {
  background-image: url("@/assets/Fondo2.jpg");
} */
</style>

<script>
import SidebarCustom from "@/components/SidebarCustom.vue";
// import HeaderCustom from "@/components/HeaderCustom.vue";
import { mapState } from "vuex";
export default {
  name: "convocatoriasView",
  data() {
    return {
      tipo: "",
      Cursos: [],

      search: "",
      searchGet: false,
      searchValues: [],

      NUM_RESULTS: 4,
      pag: 1,
      pager: 0,
    };
  },
  components: {
    // HeaderCustom,
    SidebarCustom,
  },
  computed: {
    ...mapState(["url_api", "getter"]),
  },
  methods: {
    async getTipoCur(tipo_cur) {
      try {
        let res = await this.axios.get("/api/TipoCurso/" + tipo_cur);
        this.tipo = res.data.Descripcion.tipo_conv_curso_nombre;
        this.getCursos();
      } catch (error) {
        console.log(error);
      }
    },
    async getCursos() {
      try {
        let res = await this.axios.get(
          "/api/cursosAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Cursos = [];
        res.data.forEach((cs) => {
          if (
            cs.det_estado == "1" &&
            cs.tipo_curso_otro.tipo_conv_curso_nombre == this.tipo
          ) {
            this.Cursos.push(cs);
          }
        });
        this.pager = this.Cursos.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    clickBack() {
      this.$store.commit("clickLink");
      this.$router.go(-1);
    },
    buscar() {
      if (this.search != "") {
        this.searchGet = true;

        this.searchValues = [];
        this.Cursos.forEach((cur) => {
          if (
            cur.det_titulo.toUpperCase().includes(this.search.toUpperCase())
          ) {
            this.searchValues.push(cur);
          }
        });
      } else {
        this.searchGet = false;
      }
    },
  },
  mounted() {
    this.$store.commit("loadOn");
    this.getTipoCur(this.$route.params.tipo_cur);
  },
  updated() {
    if (this.getter) {
      this.$store.commit("loadOn");
      this.getTipoCur(this.$route.params.tipo_cur);
      this.$store.state.getter = false;
    }
  },
  created() {
    this.$store.commit("loadOn");
    this.getTipoCur(this.$route.params.tipo_cur);
  },
};
</script>
